def perceive(data):
    text = str(data).strip().lower().replace(',', ' ')
    value = None
    for token in text.split():
        if token.startswith("load=") and token.split("=", 1)[1].isdigit():
            value = token.split("=", 1)[1]
        elif token.isdigit():
            value = token
    if value is None:
        return {}
    return {"load": int(value)}
